"use strict";(globalThis.webpackChunkorka_website=globalThis.webpackChunkorka_website||[]).push([[342],{8462(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/orka/docs/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"category","label":"Core Concepts","collapsed":false,"items":[{"type":"link","href":"/orka/docs/architecture","label":"Architecture","docId":"concepts/architecture","unlisted":false},{"type":"link","href":"/orka/docs/configuration","label":"Configuration","docId":"concepts/configuration","unlisted":false},{"type":"link","href":"/orka/docs/agent-runtimes","label":"Agent Runtimes","docId":"concepts/agent-runtimes","unlisted":false},{"type":"link","href":"/orka/docs/agent-sandbox","label":"Agent Sandbox Workspaces","docId":"concepts/agent-sandbox","unlisted":false},{"type":"link","href":"/orka/docs/substrate","label":"Substrate Execution Workspaces","docId":"concepts/substrate","unlisted":false},{"type":"link","href":"/orka/docs/memory","label":"Memory","docId":"concepts/memory","unlisted":false},{"type":"link","href":"/orka/docs/kontxt","label":"Kontxt TxToken integration","docId":"concepts/kontxt","unlisted":false},{"type":"link","href":"/orka/docs/security","label":"Security","docId":"concepts/security","unlisted":false}],"collapsible":true},{"type":"category","label":"Guides","collapsed":false,"items":[{"type":"link","href":"/orka/docs/chat","label":"Interactive Chat","docId":"guides/chat","unlisted":false},{"type":"link","href":"/orka/docs/multi-agent-coordination","label":"Multi-Agent Coordination","docId":"guides/multi-agent-coordination","unlisted":false},{"type":"link","href":"/orka/docs/autonomous-tasks","label":"Autonomous Task Execution","docId":"guides/autonomous-tasks","unlisted":false},{"type":"link","href":"/orka/docs/kontxt-quickstart","label":"Kontxt quickstart: use Kubernetes identity to call Orka without long-lived tokens","docId":"guides/kontxt-quickstart","unlisted":false},{"type":"link","href":"/orka/docs/repository-security-scanning","label":"Repository Security Scanning","docId":"guides/repository-security-scanning","unlisted":false},{"type":"link","href":"/orka/docs/repository-monitors","label":"Repository Monitors","docId":"guides/repository-monitors","unlisted":false},{"type":"link","href":"/orka/docs/github-label-triggers","label":"GitHub Label Triggers","docId":"guides/github-label-triggers","unlisted":false},{"type":"link","href":"/orka/docs/ui","label":"Web Dashboard","docId":"guides/ui","unlisted":false}],"collapsible":true},{"type":"category","label":"API Reference","collapsed":false,"items":[{"type":"link","href":"/orka/docs/api-reference","label":"API Reference","docId":"reference/api-reference","unlisted":false},{"type":"link","href":"/orka/docs/cli-reference","label":"CLI Reference","docId":"reference/cli","unlisted":false},{"type":"link","href":"/orka/docs/openai-compat","label":"OpenAI-Compatible API","docId":"reference/openai-compat","unlisted":false},{"type":"link","href":"/orka/docs/anthropic-compat","label":"Anthropic-Compatible API","docId":"reference/anthropic-compat","unlisted":false}],"collapsible":true},{"type":"category","label":"Development","collapsed":false,"items":[{"type":"link","href":"/orka/docs/development","label":"Development","docId":"development/development","unlisted":false},{"type":"link","href":"/orka/docs/testing","label":"Testing","docId":"development/testing","unlisted":false},{"type":"link","href":"/orka/docs/security-scanning-design","label":"Repository Security Scanning Design","docId":"development/security-scanning-design","unlisted":false}],"collapsible":true}]},"docs":{"concepts/agent-runtimes":{"id":"concepts/agent-runtimes","title":"Agent Runtimes","description":"Agent runtimes let Orka delegate task execution to external agent CLIs\u2014such as Codex CLI, Claude Code CLI, and GitHub Copilot CLI\u2014instead of running tasks through Orka\'s built-in AI worker. This gives your tasks access to full autonomous coding capabilities (file read/write/edit, bash execution, git operations) provided by battle-tested agent runtimes, while Orka handles scheduling, lifecycle management, secrets, sessions, and Kubernetes-native orchestration.","sidebar":"tutorialSidebar"},"concepts/agent-sandbox":{"id":"concepts/agent-sandbox","title":"Agent Sandbox Workspaces","description":"Agent sandbox workspace support is experimental and disabled by default. When enabled, a type: agent Task can request an upstream agent-sandbox workspace with Task.spec.execution.workspace. Orka still creates the normal Kubernetes worker Job, but the agent worker wrapper uses the resolved workspace settings to claim and wait for an agent-sandbox workspace, then runs the configured agent runtime inside that sandbox.","sidebar":"tutorialSidebar"},"concepts/architecture":{"id":"concepts/architecture","title":"Architecture","description":"Orka is a Kubernetes-native task execution platform where a controller manages Jobs and Pods for incoming task requests, supporting container tasks, AI agent tasks with LLM integration, and external agent CLI runtimes.","sidebar":"tutorialSidebar"},"concepts/configuration":{"id":"concepts/configuration","title":"Configuration","description":"Custom Resources","sidebar":"tutorialSidebar"},"concepts/kontxt":{"id":"concepts/kontxt","title":"Kontxt TxToken integration","description":"Orka can participate in kontxt transaction-token workflows without storing raw transaction tokens in Task specs/status, labels, annotations, logs, metrics, or durable memory. Delegated raw TxTokens are stored only in owner-referenced Kubernetes Secrets for worker handoff. The integration is intentionally staged so existing Kubernetes ServiceAccount and OIDC callers continue to work unless context-token authentication or authorization is explicitly configured.","sidebar":"tutorialSidebar"},"concepts/memory":{"id":"concepts/memory","title":"Memory","description":"Orka provides a namespace-scoped memory layer for AI worker tasks. It is designed for shared Kubernetes environments where memory should be useful, auditable, and safe by default.","sidebar":"tutorialSidebar"},"concepts/security":{"id":"concepts/security","title":"Security","description":"Worker Pods","sidebar":"tutorialSidebar"},"concepts/substrate":{"id":"concepts/substrate","title":"Substrate Execution Workspaces","description":"Orka can run agent Tasks inside","sidebar":"tutorialSidebar"},"development/development":{"id":"development/development","title":"Development","description":"Prerequisites","sidebar":"tutorialSidebar"},"development/security-scanning-design":{"id":"development/security-scanning-design","title":"Repository Security Scanning Design","description":"This page documents the internal design of repository security scanning: the storage model,","sidebar":"tutorialSidebar"},"development/testing":{"id":"development/testing","title":"Testing","description":"Orka has comprehensive test coverage across all packages, including unit tests, integration tests (envtest), end-to-end tests (Kind cluster), and frontend tests.","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"Orka is a Kubernetes-native platform for running AI agents and tool-using workflows as","sidebar":"tutorialSidebar"},"guides/autonomous-tasks":{"id":"guides/autonomous-tasks","title":"Autonomous Task Execution","description":"Autonomous mode enables long-running, self-driving development loops. A coordinator agent can autonomously decompose a high-level goal into sub-tasks, implement them, test, iterate, and continue working until the goal is complete.","sidebar":"tutorialSidebar"},"guides/chat":{"id":"guides/chat","title":"Interactive Chat","description":"The chat endpoint provides an agentic conversational interface where an LLM orchestrator can create and manage Kubernetes resources on the user\'s behalf. It accepts natural language, reasons about what tasks to create, and autonomously executes them using the platform.","sidebar":"tutorialSidebar"},"guides/github-label-triggers":{"id":"guides/github-label-triggers","title":"GitHub Label Triggers","description":"Orka can create an agent-runtime Task when a GitHub issue or pull request receives a label such as agentupdate-branch, agentto-issues.","sidebar":"tutorialSidebar"},"guides/kontxt-quickstart":{"id":"guides/kontxt-quickstart","title":"Kontxt quickstart: use Kubernetes identity to call Orka without long-lived tokens","description":"This guide shows one successful Orka + kontxt run using a Kubernetes projected ServiceAccount token as the caller identity. The caller runs inside the cluster, exchanges its bound ServiceAccount token for a short-lived kontxt TxToken, and calls Orka with Txn-Token.","sidebar":"tutorialSidebar"},"guides/multi-agent-coordination":{"id":"guides/multi-agent-coordination","title":"Multi-Agent Coordination","description":"Enable coordinator agents to dynamically delegate subtasks to specialist agents at runtime. The LLM decides what to delegate, to whom, and how to synthesize results. The controller enforces guardrails (allowed agents, max depth, max concurrency). Each child task is a real Kubernetes Job with full isolation.","sidebar":"tutorialSidebar"},"guides/repository-monitors":{"id":"guides/repository-monitors","title":"Repository Monitors","description":"Repository monitors are durable, Kubernetes-native PR review automation for GitHub repositories. A RepositoryMonitor stores the repository scope, review agent, schedule, and safety policy in a CRD. The controller records runs, PR inventory, review results, and audit events in the SQLite store, then exposes that state through the REST API and embedded dashboard.","sidebar":"tutorialSidebar"},"guides/repository-security-scanning":{"id":"guides/repository-security-scanning","title":"Repository Security Scanning","description":"Repository security scanning gives Orka a Codex Security-like workflow: register a GitHub","sidebar":"tutorialSidebar"},"guides/ui":{"id":"guides/ui","title":"Web Dashboard","description":"Orka includes a built-in React web dashboard embedded into the controller binary. No separate frontend deployment is needed.","sidebar":"tutorialSidebar"},"reference/anthropic-compat":{"id":"reference/anthropic-compat","title":"Anthropic-Compatible API","description":"Orka exposes an Anthropic-compatible Messages API at /anthropic/v1/messages, enabling Anthropic-compatible clients (Claude Code, etc.) to use Orka as a transparent proxy.","sidebar":"tutorialSidebar"},"reference/api-reference":{"id":"reference/api-reference","title":"API Reference","description":"The controller exposes a REST API for programmatic access. All /api/v1/* endpoints require authentication. By default Orka accepts Kubernetes ServiceAccount bearer tokens; when configured, external callers can use a valid OIDC JWT or generic context token instead.","sidebar":"tutorialSidebar"},"reference/cli":{"id":"reference/cli","title":"CLI Reference","description":"The orka CLI talks to the Orka controller REST API and is intended for day-to-day task inspection, resource CRUD, and operator workflows. It uses the same authentication and namespace rules as the API.","sidebar":"tutorialSidebar"},"reference/openai-compat":{"id":"reference/openai-compat","title":"OpenAI-Compatible API","description":"Orka exposes an OpenAI-compatible API at /openai/v1/chat/completions and /openai/v1/models, allowing any OpenAI-compatible client to use Orka as a provider. This includes tools like Continue, Cursor, and others.","sidebar":"tutorialSidebar"}}}}')}}]);